    v_party_id INTEGER;
    v_coalition_id INTEGER;
BEGIN
    -- Get or create Province
    INSERT INTO Province (Name) VALUES ('SALTA')
    ON CONFLICT DO NOTHING;
    SELECT UniqueID INTO v_province_id FROM Province WHERE Name = 'SALTA';
    
    -- Get or create Party
    INSERT INTO Party (Name) VALUES ('FRENTE DE TODOS')
    ON CONFLICT DO NOTHING;
    SELECT UniqueID INTO v_party_id FROM Party WHERE Name = 'FRENTE DE TODOS';
    
    -- Get or create Coalition
    INSERT INTO Coalition (Name) VALUES ('FRENTE DE TODOS')
    ON CONFLICT (Name) DO NOTHING;
    SELECT UniqueID INTO v_coalition_id FROM Coalition WHERE Name = 'FRENTE DE TODOS';
    
    -- Insert Representative if not exists (only if we have required fields)
    INSERT INTO Representative (
        External_id,
        Full_name,
        Last_name,
        First_name,
        Province_id,
        Party_id,
        Coalition_id,
        Legal_start_date,
        Legal_end_date,
        Real_start_date,
        Real_end_date,
        Email,
        Phone,
        Facebook_url,
        Twitter_url,
