    v_province_id INTEGER;
    v_party_id INTEGER;
    v_coalition_id INTEGER;
BEGIN
    -- Get or create Province
    INSERT INTO Province (Name) VALUES ('NEUQUÉN')
    ON CONFLICT DO NOTHING;
    SELECT UniqueID INTO v_province_id FROM Province WHERE Name = 'NEUQUÉN';
    
    -- Get or create Party
    INSERT INTO Party (Name) VALUES ('FRENTE DE TODOS')
    ON CONFLICT DO NOTHING;
    SELECT UniqueID INTO v_party_id FROM Party WHERE Name = 'FRENTE DE TODOS';
    
    -- Get or create Coalition
    INSERT INTO Coalition (Name) VALUES ('UNIDAD CIUDADANA')
    ON CONFLICT (Name) DO NOTHING;
    SELECT UniqueID INTO v_coalition_id FROM Coalition WHERE Name = 'UNIDAD CIUDADANA';
    
    -- Insert Representative if not exists (only if we have required fields)
    INSERT INTO Representative (
        External_id,
        Full_name,
        Last_name,
        First_name,
        Province_id,
        Party_id,
        Coalition_id,
        Legal_start_date,
        Legal_end_date,
        Real_start_date,
        Real_end_date,
        Email,
        Phone,
        Facebook_url,
        Twitter_url,
        Instagram_url,
        Youtube_url
    )
    SELECT
        '251',
        'SAPAG SILVIA ESTELA ',
        'SAPAG',
        'SILVIA ESTELA ',
        v_province_id,
        v_party_id,
        v_coalition_id,
        '2019-12-10',
        '2025-12-09',
        '2019-12-10',
        NULL,
        'silvia.sapag@senado.gob.ar',
        '3556 / 3557',
        NULL,
        'https://twitter.com/sapag_silvia',
        'https://www.instagram.com/silviasapag',
        NULL
    WHERE NOT EXISTS (
        SELECT 1 FROM Representative 
        WHERE Last_name = 'SAPAG' 
        AND First_name = 'SILVIA ESTELA '
        AND Legal_start_date = '2019-12-10'
        AND Province_id = v_province_id
    );
END $$;


